  ('bookkeeper-moex-01682', 'bookkeeper', 'bookkeeper-moex-101-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國商業會計法之規定，會計事項應按發生次序逐日登帳，至遲不得超過多久的時間？', '["10天", "20天", "1個月", "2個月"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "acbcc7ff0a91", "answer_pdf_sha1": "82fc343096c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01683', 'bookkeeper', 'bookkeeper-moex-101-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國商業會計法之規定，下列有關會計憑證與帳簿之敘述，何者錯誤？', '["各項會計憑證，除應永久保存或有關未結會計事項者外，應於年度決算程序辦理終了後，至少保存五年", "各項會計帳簿及財務報表，應於年度決算程序辦理終了後，至少保存五年", "會計憑證，應按日或按月裝訂成冊，有原始憑證者，應附於記帳憑證之後", "會計事項應取得並可取得之會計憑證，如因經辦或主管該項人員之故意或過失，致該項會計憑證毀損、 缺少或滅失而致商業遭受損害時，該經辦或主管人員應負賠償之責"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "acbcc7ff0a91", "answer_pdf_sha1": "82fc343096c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01684', 'bookkeeper', 'bookkeeper-moex-101-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國商業會計法之規定，資產之取得以現金以外之其他資產或承擔負債交換者，以公平價值入帳為 原則。公平價值無法可靠衡量時，應如何處理？', '["按換入資產之帳面金額減去支付之現金，作為換入資產成本", "按換入資產之帳面金額作為換入資產成本", "按換出資產之帳面金額加支付之現金，或減去收到之現金，作為換入資產成本", "依其取得價格加上自取得至適於營業上使用或出售之一切必要而合理之支出，作為換入資產成本"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "acbcc7ff0a91", "answer_pdf_sha1": "82fc343096c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01685', 'bookkeeper', 'bookkeeper-moex-101-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '有關庫藏股帳面價值之計算，依商業會計處理準則第27條規定應採：', '["加權平均法", "先進先出法", "個別認定法", "後進先出法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "acbcc7ff0a91", "answer_pdf_sha1": "82fc343096c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01686', 'bookkeeper', 'bookkeeper-moex-101-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國商業會計法之規定，下列有關存貨評價與處理之敘述，何者錯誤？', '["商品存貨、存料、在製品、製成品、副產品等存貨之衡量，以實際成本為原則；成本高於淨變現價值 時，應以淨變現價值為準", "所稱淨變現價值，係指企業預期正常營業出售存貨所能取得之淨額", "成本之計算得按存貨之種類或性質，採用個別辨認法、先進先出法、加權平均法、移動平均法或其他 經主管機關核定之方法計算之", "存貨跌價損失應列為營業費用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "acbcc7ff0a91", "answer_pdf_sha1": "82fc343096c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01687', 'bookkeeper', 'bookkeeper-moex-101-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國商業會計法之規定，下列敘述何者錯誤？', '["購入之商譽、商標權、專利權、著作權、特許權及其他等無形資產，應以實際成本為取得成本", "無形資產以自行發展取得者，應以所發生之研究支出及發展支出作為取得成本", "無形資產之經濟效益期限可合理估計者，應按照效益存續期限攤銷", "商譽及其他經濟效益期限無法合理估計之無形資產，應定期評估其價值，如有減損，損失應予認列"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "acbcc7ff0a91", "answer_pdf_sha1": "82fc343096c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01688', 'bookkeeper', 'bookkeeper-moex-101-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國商業會計法之規定，下列有關資產重估價之會計處理，何者錯誤？', '["固定資產、遞耗資產及無形資產，得依法令規定辦理資產重估價", "自用土地得按公告現值調整之", "辦理固定資產重估或調整而發生之增值，應列為業主權益項下之未實現重估增值", "經重估之資產，應按其重估後之價額入帳，但其折舊、折耗或攤銷之計提，均應以重估前價值為基礎， 繼續提列折舊"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "acbcc7ff0a91", "answer_pdf_sha1": "82fc343096c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01689', 'bookkeeper', 'bookkeeper-moex-101-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '商業負責人應於會計年度終了後多久時間內，將商業之決算報表提請商業出資人、合夥人或股東承認？', '["二個月內", "三個月內", "六個月內", "一年內"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "acbcc7ff0a91", "answer_pdf_sha1": "82fc343096c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01690', 'bookkeeper', 'bookkeeper-moex-101-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國商業會計法之規定，下列敘述何者錯誤？', '["未依法取得代他人處理會計事務之資格而擅自代他人處理商業會計事務者，處新臺幣十萬元以下罰金", "未依法取得代他人處理會計事務之資格而擅自代他人處理商業會計事務者，經查獲後三年內再犯者， 處一年以下有期徒刑、拘役或科或併科新臺幣十萬元以下罰金", "商業負責人、主辦及經辦會計人員或依法受託代他人處理會計事務之人員，偽造或變造會計憑證、會 計帳簿報表內容或毀損其頁數者，處五年以下有期徒刑、拘役或科或併科新臺幣六十萬元以下罰金", "使用電子方式處理會計資料之商業，其商業負責人、主辦及經辦會計人員或以電子方式處理會計資料 之有關人員故意登錄或輸入不實資料，處五年以下有期徒刑、拘役或科或併科新臺幣六十萬元以下罰金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "acbcc7ff0a91", "answer_pdf_sha1": "82fc343096c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
